import React from 'react';
import { CartItem } from '../types';

interface CartSidebarProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onUpdateQuantity: (id: string, delta: number) => void;
  onCheckout: () => void;
}

const CartSidebar: React.FC<CartSidebarProps> = ({ isOpen, onClose, items, onUpdateQuantity, onCheckout }) => {
  const subtotal = items.reduce((acc, item) => acc + item.price * item.quantity, 0);
  const delivery = items.length > 0 ? 5.00 : 0;
  const tax = subtotal * 0.1;
  const total = subtotal + delivery + tax;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex justify-end">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />
      <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col transform transition-transform duration-300">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <h2 className="text-2xl font-bold text-slate-800">Your Basket</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full">
            <i className="fa-solid fa-xmark text-xl"></i>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {items.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400">
              <i className="fa-solid fa-utensils text-5xl mb-4 opacity-20"></i>
              <p>Your basket is empty</p>
            </div>
          ) : (
            items.map((item) => (
              <div key={item.id} className="flex gap-4">
                <div className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0">
                  <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1">
                  <h4 className="font-bold text-slate-800">{item.name}</h4>
                  <p className="text-xs text-slate-500 mb-2">${item.price.toFixed(2)} each</p>
                  <div className="flex items-center gap-3">
                    <button 
                      onClick={() => onUpdateQuantity(item.id, -1)}
                      className="w-8 h-8 rounded-full border border-gray-200 flex items-center justify-center hover:bg-gray-50"
                    >
                      <i className="fa-solid fa-minus text-xs"></i>
                    </button>
                    <span className="font-bold text-sm w-4 text-center">{item.quantity}</span>
                    <button 
                      onClick={() => onUpdateQuantity(item.id, 1)}
                      className="w-8 h-8 rounded-full bg-[#064E3B] text-white flex items-center justify-center hover:bg-[#065F46]"
                    >
                      <i className="fa-solid fa-plus text-xs"></i>
                    </button>
                  </div>
                </div>
                <div className="text-right font-bold text-slate-800">
                  ${(item.price * item.quantity).toFixed(2)}
                </div>
              </div>
            ))
          )}
        </div>

        {items.length > 0 && (
          <div className="p-6 bg-gray-50 border-t border-gray-100 space-y-4">
            <div className="space-y-2 text-sm text-slate-600">
              <div className="flex justify-between">
                <span>Subtotal</span>
                <span>${subtotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>Delivery Fee</span>
                <span>${delivery.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>Estimated Tax (10%)</span>
                <span>${tax.toFixed(2)}</span>
              </div>
            </div>
            <div className="flex justify-between text-xl font-bold text-slate-900 pt-2 border-t border-gray-200">
              <span>Total</span>
              <span>${total.toFixed(2)}</span>
            </div>
            <button 
              onClick={onCheckout}
              className="w-full bg-[#064E3B] text-white py-4 rounded-2xl font-bold text-lg hover:bg-[#065F46] transition-all flex items-center justify-center gap-3 shadow-xl shadow-emerald-900/20"
            >
              Checkout Now
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default CartSidebar;

import React, { useState, useEffect, useRef } from 'react';
import { chatWithAssistant, processVoiceOrder } from '../services/geminiService';

interface AIAssistantProps {
  onOrderCommand: (item: string, qty: number) => void;
  cart: any[];
}

const AIAssistant: React.FC<AIAssistantProps> = ({ onOrderCommand, cart }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: "Hello! I'm OLIF, your premium dining assistant. How can I help you today?" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async (text: string) => {
    if (!text.trim()) return;
    setMessages(prev => [...prev, { role: 'user', text }]);
    setInput('');
    setLoading(true);

    try {
      const response = await chatWithAssistant(text, { cart });
      setMessages(prev => [...prev, { role: 'ai', text: response || "I'm sorry, I couldn't process that." }]);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const startVoice = () => {
    if (!('webkitSpeechRecognition' in window)) {
      alert("Voice features not supported in this browser.");
      return;
    }

    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.lang = 'en-US';
    recognition.start();
    setIsListening(true);

    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      setMessages(prev => [...prev, { role: 'user', text: `[Voice] ${transcript}` }]);

      setLoading(true);
      const voiceResult = await processVoiceOrder(transcript);
      if (voiceResult.isOrder) {
        onOrderCommand(voiceResult.item, voiceResult.quantity);
        setMessages(prev => [...prev, { role: 'ai', text: `Understood. I've added ${voiceResult.quantity}x ${voiceResult.item} to your basket.` }]);
      } else {
        const aiResponse = await chatWithAssistant(transcript, { cart });
        setMessages(prev => [...prev, { role: 'ai', text: aiResponse || "I heard you, but I'm not sure what you need." }]);
      }
      setLoading(false);
    };

    recognition.onerror = () => setIsListening(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100]">
      {isOpen ? (
        <div className="w-80 md:w-96 bg-white rounded-3xl shadow-2xl overflow-hidden flex flex-col border border-gray-100 transform animate-in slide-in-from-bottom-4 duration-300">
          <div className="p-4 bg-[#064E3B] text-white flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-full bg-[#D4AF37] flex items-center justify-center text-xs font-bold">O</div>
              <div>
                <p className="font-bold text-sm">OLIF AI Assistant</p>
                <p className="text-[10px] opacity-70">Always at your service</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:opacity-70">
              <i className="fa-solid fa-minus"></i>
            </button>
          </div>

          <div ref={scrollRef} className="h-80 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-4 py-2 rounded-2xl text-sm ${
                  m.role === 'user' 
                  ? 'bg-[#064E3B] text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 shadow-sm border border-gray-100 rounded-tl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-white px-4 py-2 rounded-2xl shadow-sm border border-gray-100">
                  <div className="flex gap-1">
                    <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce delay-100"></div>
                    <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce delay-200"></div>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-gray-100 flex gap-2">
            <input 
              type="text" 
              placeholder="Type or use voice..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSendMessage(input)}
              className="flex-1 bg-gray-100 border-none rounded-xl px-4 py-2 text-sm focus:ring-1 focus:ring-[#064E3B]"
            />
            <button 
              onClick={startVoice}
              className={`w-10 h-10 rounded-xl flex items-center justify-center transition-colors ${
                isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 text-[#064E3B] hover:bg-gray-200'
              }`}
            >
              <i className="fa-solid fa-microphone"></i>
            </button>
            <button 
              onClick={() => handleSendMessage(input)}
              className="w-10 h-10 bg-[#064E3B] text-white rounded-xl flex items-center justify-center hover:bg-[#065F46]"
            >
              <i className="fa-solid fa-paper-plane"></i>
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-[#064E3B] text-white rounded-full flex items-center justify-center shadow-2xl hover:scale-110 transition-transform relative group"
        >
          <div className="absolute -top-12 right-0 bg-white text-slate-800 text-xs py-2 px-4 rounded-xl shadow-xl opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
            Need help ordering? 🍲
          </div>
          <i className="fa-solid fa-comment-dots text-2xl"></i>
          <span className="absolute -top-1 -right-1 w-4 h-4 bg-[#D4AF37] rounded-full border-2 border-[#064E3B]"></span>
        </button>
      )}
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import RestaurantCard from './components/RestaurantCard';
import CartSidebar from './components/CartSidebar';
import AIAssistant from './components/AIAssistant';
import { MOCK_RESTAURANTS, COLORS } from './constants';
import { Restaurant, CartItem, UserRole, FoodCategory, MenuItem } from './types';
import { getFoodRecommendations } from './services/geminiService';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.Customer);
  const [selectedCategory, setSelectedCategory] = useState<FoodCategory | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [recommendations, setRecommendations] = useState<any[]>([]);
  const [loadingRecs, setLoadingRecs] = useState(false);

  useEffect(() => {
    const fetchRecs = async () => {
      setLoadingRecs(true);
      try {
        const recs = await getFoodRecommendations("A fan of healthy and spicy African food looking for a premium experience.");
        setRecommendations(recs);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingRecs(false);
      }
    };
    fetchRecs();
  }, []);

  const addToCart = (item: MenuItem, restaurantId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1, restaurantId }];
    });
    setIsCartOpen(true);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(0, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }).filter(i => i.quantity > 0));
  };

  const filteredRestaurants = MOCK_RESTAURANTS.filter(res => {
    const matchesCategory = selectedCategory === 'All' || res.categories.includes(selectedCategory as FoodCategory);
    const matchesSearch = res.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const handleVoiceOrder = (itemName: string, qty: number) => {
    // Basic search for the item across restaurants
    for (const res of MOCK_RESTAURANTS) {
      const item = res.menu.find(m => m.name.toLowerCase().includes(itemName.toLowerCase()));
      if (item) {
        for(let i=0; i<qty; i++) addToCart(item, res.id);
        break;
      }
    }
  };

  // Simplified view renderers based on role
  const renderContent = () => {
    switch(currentRole) {
      case UserRole.Vendor:
        return (
          <div className="p-8">
            <h2 className="text-3xl font-bold mb-8">Vendor Dashboard</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-slate-500 text-sm font-medium">Pending Orders</p>
                <p className="text-4xl font-bold text-[#064E3B]">12</p>
              </div>
              <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-slate-500 text-sm font-medium">Sales Today</p>
                <p className="text-4xl font-bold text-[#D4AF37]">$1,240.50</p>
              </div>
              <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-slate-500 text-sm font-medium">Top Item</p>
                <p className="text-xl font-bold text-slate-800">Jollof Rice</p>
              </div>
            </div>
          </div>
        );
      case UserRole.Rider:
        return (
          <div className="p-8">
            <h2 className="text-3xl font-bold mb-8">Rider App</h2>
            <div className="bg-white rounded-3xl shadow-xl overflow-hidden h-[500px] relative">
              <div className="absolute inset-0 bg-slate-200 flex items-center justify-center italic text-slate-400">
                Map View (Simulated)
              </div>
              <div className="absolute bottom-6 left-6 right-6 bg-white p-6 rounded-2xl shadow-2xl">
                <div className="flex justify-between items-center">
                  <div>
                    <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Active Job</p>
                    <p className="text-lg font-bold">Delivery to 12 Luxury Heights</p>
                  </div>
                  <button className="bg-[#064E3B] text-white px-6 py-2 rounded-xl font-bold">Mark Delivered</button>
                </div>
              </div>
            </div>
          </div>
        );
      case UserRole.Admin:
        return (
          <div className="p-8">
            <h2 className="text-3xl font-bold mb-8">Global Analytics</h2>
            <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
              <div className="h-64 bg-gray-50 rounded-2xl flex items-end justify-between p-4 gap-2">
                {[40, 60, 45, 90, 100, 80, 50].map((h, i) => (
                  <div key={i} style={{ height: `${h}%` }} className="w-full bg-[#064E3B] rounded-t-lg opacity-80"></div>
                ))}
              </div>
              <p className="text-center mt-4 text-sm text-slate-500">System Traffic (Past 7 Days)</p>
            </div>
          </div>
        );
      default:
        return (
          <div className="max-w-7xl mx-auto px-6 py-12">
            {/* AI Recommendations Section */}
            {!loadingRecs && recommendations.length > 0 && (
              <section className="mb-16">
                <h2 className="text-sm font-bold text-[#D4AF37] uppercase tracking-[0.2em] mb-4">Curated for You</h2>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {recommendations.map((rec, i) => (
