        {/* Restaurant Listing */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredRestaurants.map(res => (
            <div key={res.id}>
              <RestaurantCard 
                restaurant={res} 
                onClick={openRestaurant}
              />
              <div className="mt-4 space-y-2">
                {res.menu.slice(0, 2).map(item => (
