    const fetchRecs = async () => {
      setLoadingRecs(true);
      try {
        const recs = await getFoodRecommendations("A fan of healthy and spicy local Nigerian food looking for a premium experience.");
        setRecommendations(recs);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingRecs(false);
      }
    };
    fetchRecs();
